let allData = {{workflowparams:allData}}
const saveAs = {{workflowparams:saveAs}}
const updatedPRT = []

const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(3);
};

const lines = allData.table_prt || [];
for (const prtLineItem of lines) {
  // For a completed return, drop zero-return-qty lines (the client already
  // confirmed their removal). Drafts keep every line.
  if (saveAs !== "Draft" && !(parseFloat(prtLineItem.return_quantity) > 0)) continue;

  prtLineItem.return_quantity = formatNumber(prtLineItem.return_quantity);
  prtLineItem.received_qty = formatNumber(prtLineItem.received_qty);
  prtLineItem.unit_price = formatNumber(prtLineItem.unit_price);

  prtLineItem.supplier_id = allData.supplier_id || null;
  prtLineItem.plant_id = allData.plant || null;
  prtLineItem.billing_state_id = allData.billing_address_state || null;
  prtLineItem.billing_country_id = allData.billing_address_country || null;
  prtLineItem.shipping_state_id = allData.shipping_address_state || null;
  prtLineItem.shipping_country_id = allData.shipping_address_country || null;
  prtLineItem.organization_id = allData.organization_id;

  updatedPRT.push(prtLineItem);
}

updatedPRT.forEach((line, index) => { line.line_index = index + 1; });
allData.table_prt = updatedPRT;

allData.po_id = [...new Set(updatedPRT.map((r) => r.po_id).filter((x) => x))];
allData.gr_id = [...new Set(updatedPRT.map((r) => r.gr_id).filter((x) => x))];
allData.po_no_display = [...new Set(updatedPRT.map((r) => r.po_number).filter((x) => x))].join(", ");
allData.gr_no_display = [...new Set(updatedPRT.map((r) => r.gr_number).filter((x) => x))].join(", ");

if (saveAs === "Draft") {
  if (allData.purchase_return_no_type !== -9999 && (!allData.purchase_return_no || allData.purchase_return_no === null || allData.purchase_return_no === "")) {
    allData.purchase_return_no = "draft";
  }
} else {
  if (allData.purchase_return_no_type !== -9999 && (!allData.purchase_return_no || allData.purchase_return_no === null || allData.purchase_return_no === "" || allData.previous_status === "Draft")) {
    allData.purchase_return_no = "issued";
  }
}

allData.purchase_return_status = saveAs === "Draft" ? "Draft" : "Issued";

if (allData.acc_integration_type && allData.acc_integration_type !== "No Accounting Integration") {
  allData.posted_status = "Unposted";
}

return {
  allData: allData,
  purchase_return_status: allData.purchase_return_status,
}

return {
  required_fields: JSON.stringify([
    { name: "plant", label: "Plant" },
    { name: "purchase_return_no", label: "Purchase Return No" },
    {
      name: "table_prt",
      label: "Item Information",
      isArray: true,
      arrayType: "object",
      arrayFields: [],
    },
  ]),
  data: JSON.stringify({
    plant: {{node:code_node_ISWz5KGY.data.allData.plant}},
    purchase_return_no: {{node:code_node_ISWz5KGY.data.allData.purchase_return_no}},
    table_prt: {{node:code_node_ISWz5KGY.data.allData.table_prt}}
  })
}

const allData = {{node:code_node_ISWz5KGY.data.allData}}
const subformData = allData.table_prt || []

let quantityFailed = 0
let quantityMessage

const hasQuantity = subformData.some((line) => {
  if (!line.temp_qty_data) return false;
  try {
    const parsed = JSON.parse(line.temp_qty_data);
    return Array.isArray(parsed) && parsed.some(
      (entry) => entry.return_quantity && parseFloat(entry.return_quantity) > 0
    );
  } catch (e) {
    return false;
  }
});

if (!hasQuantity) {
  quantityFailed = 1
  quantityMessage = 'No quantity selected to return'
}

return { quantityFailed: quantityFailed, quantityMessage: quantityMessage };

const page_status = {{workflowparams:pageStatus}};
const allData = {{node:code_node_ISWz5KGY.data.allData}}
const subformData = allData.table_prt;

const plant_id = allData.plant;
const organization_id = allData.organization_id;
const purchase_return_no = allData.purchase_return_no;
const doc_date = allData.purchase_return_date;

const item = {{node:loop_C4YuLV2v}};
const material_id = item.material_id;
const material_uom = item.return_uom_id;
const total_quantity = item.return_quantity;
const location_id = item.location_id;
const batch_id = item.batch_id || null;
const inventory_category = "Unrestricted";

let balancesToProcess = [];
const tempData = item.temp_qty_data;
if (tempData) {
  try {
    const parsed = JSON.parse(tempData);
    if (Array.isArray(parsed)) {
      balancesToProcess = parsed.filter(
        (entry) => entry.return_quantity && parseFloat(entry.return_quantity) > 0
      );
    }
  } catch (e) {
    balancesToProcess = [];
  }
}

return {
  plant_id: plant_id,
  organization_id: organization_id,
  purchase_return_no: purchase_return_no,
  page_status: page_status,
  material_id: material_id,
  material_uom: material_uom,
  total_quantity: total_quantity,
  location_id: location_id,
  batch_id: batch_id,
  inventory_category: inventory_category,
  doc_date: doc_date,
  balancesToProcess: balancesToProcess
};

const balance = {{node:loop_9XodkC0Z}};
const batch_id = balance.batch_id || null;
const location_id = balance.location_id;
const quantity = balance.return_quantity;
const inventory_category = balance.inventory_category;
const manufacturing_date = balance.manufacturing_date || null;
const expired_date = balance.expired_date || null;
const handling_unit_id = balance.handling_unit_id || null;

return {
  batch_id: batch_id,
  location_id: location_id,
  quantity: quantity,
  inventory_category: inventory_category,
  manufacturing_date: manufacturing_date,
  expired_date: expired_date,
  handling_unit_id: handling_unit_id
};

const page_status = {{workflowparams:pageStatus}};
let allData;
if (page_status === "Add") {
  const rawData = {{node:add_node_1p1Kdkhz.data}}
  allData = Array.isArray(rawData) ? rawData[0] : rawData;
} else if (page_status === "Edit") {
  allData = {{node:get_node_7CFMbGI0.data.data}}
} else {
  allData = {{node:code_node_ISWz5KGY.data.allData}}
}

const plant_id = allData.plant;
const organization_id = allData.organization_id;
const purchase_return_no = allData.purchase_return_no;
const doc_date = allData.purchase_return_date;

const item = {{node:loop_BBZNjfzE}};
const material_id = item.material_id;
const material_uom = item.return_uom_id;
const total_quantity = item.return_quantity;
const location_id = item.location_id;
const batch_id = item.batch_id || null;
const parentNo = item.gr_number || item.po_no_display || allData.po_no_display || null;
const inventory_category = "Unrestricted";

let balancesToProcess = [];
const tempData = item.temp_qty_data;
if (tempData) {
  try {
    const parsed = JSON.parse(tempData);
    if (Array.isArray(parsed)) {
      balancesToProcess = parsed.filter(
        (entry) => entry.return_quantity && parseFloat(entry.return_quantity) > 0
      );
    }
  } catch (e) {
    balancesToProcess = [];
  }
}

balancesToProcess = balancesToProcess.map((entry) => ({ ...entry, po_no: parentNo }));

return {
  plant_id: plant_id,
  organization_id: organization_id,
  purchase_return_no: purchase_return_no,
  page_status: page_status,
  material_id: material_id,
  material_uom: material_uom,
  total_quantity: total_quantity,
  location_id: location_id,
  batch_id: batch_id,
  inventory_category: inventory_category,
  doc_date: doc_date,
  balancesToProcess: balancesToProcess
};

const balance = {{node:loop_NWeT5dSb}};
const batch_id = balance.batch_id || null;
const location_id = balance.location_id;
const quantity = balance.return_quantity;
let inventory_category = balance.inventory_category || "Unrestricted";
const manufacturing_date = balance.manufacturing_date || null;
const expired_date = balance.expired_date || null;
const po_no = balance.po_no || null;

return {
  batch_id: batch_id,
  location_id: location_id,
  quantity: quantity,
  inventory_category: inventory_category,
  manufacturing_date: manufacturing_date,
  expired_date: expired_date,
  index: 0,
  po_no: po_no
};

const allData = {{node:code_node_ISWz5KGY.data.allData}};
const subformData = allData.table_prt || [];
const plantId = allData.plant;
const organizationId = allData.organization_id;

const huUpdatesMap = new Map();
for (const line of subformData) {
  if (!line.temp_qty_data) continue;
  let entries;
  try {
    entries = JSON.parse(line.temp_qty_data);
  } catch (e) {
    continue;
  }
  if (!Array.isArray(entries)) continue;

  for (const entry of entries) {
    const huId = entry.handling_unit_id;
    if (!huId) continue;
    const qty = parseFloat(entry.return_quantity || 0);
    if (qty <= 0) continue;

    if (!huUpdatesMap.has(huId)) {
      huUpdatesMap.set(huId, {
        handling_unit_id: huId,
        plant_id: plantId,
        organization_id: organizationId,
        location_id: entry.location_id || null,
        storage_location_id: entry.storage_location_id || null,
        items: [],
      });
    }
    const update = huUpdatesMap.get(huId);

    const key = `${entry.material_id}__${entry.balance_id || ""}__${entry.batch_id || ""}`;
    const existing = update.items.find(
      (i) => `${i.material_id}__${i.balance_id || ""}__${i.batch_id || ""}` === key
    );
    if (existing) {
      existing.quantity += qty;
    } else {
      update.items.push({
        material_id: entry.material_id,
        balance_id: entry.balance_id || "",
        batch_id: entry.batch_id || null,
        quantity: qty,
      });
    }
  }
}

return {
  huUpdates: Array.from(huUpdatesMap.values()),
  huUpdatesLength: huUpdatesMap.size,
};

const u = {{node:loop_ONoGvpqr}};
return {
  handling_unit_id: u.handling_unit_id,
  plant_id: u.plant_id,
  organization_id: u.organization_id,
  location_id: u.location_id,
  storage_location_id: u.storage_location_id,
  table_hu_items: u.items,
};

const line = {{node:loop_PRTpoSync}} || {};
return {
  po_line_id: line.po_line_id || "",
  line_return_qty: parseFloat(line.return_quantity || 0)
};

let poLine = {{node:get_node_PRTpoLine.data.data}};
if (Array.isArray(poLine)) poLine = poLine[0] || {};
poLine = poLine || {};
const add = parseFloat({{node:code_node_PRTpoPrep.data.line_return_qty}} || 0);
const cur = poLine.return_quantity ? parseFloat(poLine.return_quantity) : 0;
return { newReturnQty: parseFloat((cur + add).toFixed(3)) };

let gr = {{node:get_node_PRTgr.data.data}};
if (Array.isArray(gr)) gr = gr[0] || {};
gr = gr || {};
const prt = {{node:code_node_ISWz5KGY.data.allData.table_prt}} || [];
const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));
const items = (gr.table_gr || []).map((it) => ({ ...it }));
for (const line of prt) {
  if (line.gr_id !== gr.id) continue;
  const i = items.findIndex((it) => it.id === line.gr_line_id);
  if (i >= 0) items[i].return_quantity = roundQty((items[i].return_quantity || 0) + parseFloat(line.return_quantity || 0));
}
let fully = 0, partially = 0;
const total = items.length;
for (const it of items) {
  const rq = parseFloat(it.return_quantity || 0);
  if (rq > 0) { partially++; if (rq >= parseFloat(it.received_qty || 0)) fully++; }
}
const status = (total > 0 && fully === total) ? "Fully Returned" : (partially > 0 ? "Partially Returned" : "");
return { table_gr: items, return_status: status };

const tablePRT = {{node:code_node_ISWz5KGY.data.allData.table_prt}}

const uniqueItemIds = [
  ...new Set(
    tablePRT
      .filter((item) => item.material_id)
      .map((item) => item.material_id),
  ),
];

const date = new Date().toISOString();
const updates = [];
for (const itemId of uniqueItemIds) {
  updates.push({ id: itemId, last_transaction_date: date });
}

return { updates: updates };
